  const testUser = { id: '1', name: 'John', email: 'john@test.com', role: 'admin' };

  beforeAll(async () => {
    db = new Database();
    await db.connect();
    await db.seed([testUser]);
  });

  beforeEach(() => {
    emailService = new EmailService();
    logger = new Logger();
    vi.spyOn(emailService, 'send');
    vi.spyOn(logger, 'info');
    service = new UserService(db, emailService, logger);
  });

  test('register', async () => {
    const input = { name: 'Jane', email: 'jane@test.com', password: 'pass123' };
